INSERT INTO `tests` VALUES (1,3,'MVC Concepts Test',30,'Test your knowledge of MVC architecture including Model, View, and Controller roles.','BEGINNER','2026-03-23 18:00:08','1',NULL),(2,3,'Razor Syntax Test',20,'Covers Razor syntax, directives, and ASP.NET view engine concepts.','INTERMEDIATE','2026-03-23 18:00:08','1',NULL),(3,3,'Middleware Pipeline Test',25,'Focus on middleware pipeline, request handling, and execution flow.','BEGINNER','2026-03-23 18:00:08','1',NULL),(4,3,'Dependency Injection Test',40,'Covers Dependency Injection, service lifetimes, and design principles.','ADVANCE','2026-03-23 18:00:08','1',NULL),(5,3,'Kestrel & Hosting Test',35,'Includes Kestrel server, hosting models, and web server concepts.','ADVANCE','2026-03-23 18:00:08','1',NULL),(6,5,'Overloading concept',30,'Solve MCQs on Overloading concept.','INTERMEDIATE','2026-03-26 14:55:09','1',NULL),(7,5,'Programming Fundamentals Assessment',45,'A comprehensive test covering basic programming concepts including variables, data types, control structures, and simple algorithms. Ideal for beginners starting their coding journey.','BEGINNER','2026-03-26 15:00:00','1',NULL),(8,5,'Advanced Problem Solving Challenge',60,'An intermediate-level assessment focusing on algorithmic thinking, data structures, optimization techniques, and complex problem-solving scenarios. Designed for developers with foundational knowledge.','INTERMEDIATE','2026-03-26 15:30:00','1',NULL),(9,5,'Object cloning.',30,'Solve MCQs on object cloning,','BEGINNER','2026-03-26 15:16:41','1',NULL),(10,5,'Generic colletions',30,'Solve MCQs on Generic collections.','BEGINNER','2026-03-26 17:22:31','1',NULL),(11,5,'Data Structures and Algorithms Mastery',45,'A comprehensive test covering basic programming concepts including variables, data types, control structures, and simple algorithms. Ideal for beginners starting their coding journey.','BEGINNER','2026-03-26 15:00:00','1',NULL),(12,5,'Web Development Essentials',60,'An intermediate-level assessment focusing on HTML,CSS','INTERMEDIATE','2026-03-26 15:30:00','1',NULL),(13,2,'Node.js screening',30,'Test to check the level of a student','BEGINNER','2026-04-01 15:20:58','1',NULL),(14,2,'Node.js Beginner Test',30,'A comprehensive test covering Node.js Beginner level concepts and check preparation for collective all around NodeJS skill','BEGINNER','2026-04-01 15:21:56','1',NULL),(15,2,'Node.js Event-Driven Assessment',30,'A comprehensive test covering Node.js event-driven programming and file I/O concepts.','INTERMEDIATE','2026-04-01 15:23:11','1',NULL),(16,2,'Node JS Test',20,'This test evaluates the understanding of Node.js concepts .','INTERMEDIATE','2026-04-01 15:25:45','1',NULL),(17,2,'Node.js Callback MCQ Test',30,'Test on callback functions in Node.js','BEGINNER','2026-04-01 15:28:25','1',NULL),(18,2,'Node.js Core Concepts MCQ Test',30,'A 10-question MCQ test covering Node.js fundamentals including async programming, event loop, Express.js, callbacks, and server creation.','INTERMEDIATE','2026-04-01 15:29:43','1',NULL),(19,2,'Express.js Fundamentals',30,'Focuses on routing, middleware, and REST APIs in Express.js.','BEGINNER','2026-04-01 15:33:55','1',NULL),(20,2,'Node js Request and response mcq test',30,'Test your knowledge of Node js','INTERMEDIATE','2026-04-01 15:34:28','1',NULL),(21,2,'node module MCQ Test',45,'Test on Node.js modules and their usage MCQ TEST.','INTERMEDIATE','2026-04-01 15:38:48','1',NULL),(22,2,'Node js package.json MCQ test',30,'Test your knowledge of Node js','INTERMEDIATE','2026-04-01 15:46:39','1',NULL),(23,2,'Node js asyc await mcq test',45,'Evaluate your knowledge of Node.js','BEGINNER','2026-04-01 16:00:46','1',NULL),(26,2,'Express.js Intermediate Assessment',30,'Test covering middleware, routing, security, and advanced Express.js concepts.','INTERMEDIATE','2026-04-01 16:06:25','1',NULL),(27,2,' module Test MCQ',45,'Test on Node.js modules and their usage.','INTERMEDIATE','2026-04-01 16:09:36','1',NULL),(28,2,'Java Basics MCQ Test',30,'Test covering Java OOP concepts','BEGINNER','2026-04-10 10:51:39','1',NULL),(29,1,'C# Basic Test',60,NULL,'BEGINNER','2026-04-22 13:01:18','1',NULL);
